#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int M; scanf("%d",&M);
        int *subset = (int*)malloc(M*sizeof(int));
        for(int i=0;i<M;i++) scanf("%d",&subset[i]);
        int N; scanf("%d",&N);
        int *full = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&full[i]);
        // map values (0..10000) to next greater, initialise -1
        int *next = (int*)malloc(10001*sizeof(int));
        for(int i=0;i<=10000;i++) next[i] = -1;
        int *stack = (int*)malloc(N*sizeof(int));
        int top = -1;
        for(int i=0;i<N;i++){
            int cur = full[i];
            while(top>=0 && stack[top] < cur){
                next[stack[top--]] = cur;
            }
            stack[++top] = cur;
        }
        // remaining elements already -1
        for(int i=0;i<M;i++){
            if(i) printf(" ");
            printf("%d", next[subset[i]]);
        }
        printf("\n");
        free(subset); free(full); free(next); free(stack);
    }
    return 0;
}

