import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int M = Integer.parseInt(br.readLine().trim());
            int[] subset = new int[M];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < M; i++) subset[i] = Integer.parseInt(st.nextToken());
            int N = Integer.parseInt(br.readLine().trim());
            int[] full = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) full[i] = Integer.parseInt(st.nextToken());
            Map<Integer,Integer> nxt = new HashMap<>();
            Deque<Integer> stack = new ArrayDeque<>();
            for (int x : full) {
                while (!stack.isEmpty() && stack.peekLast() < x) {
                    nxt.put(stack.pollLast(), x);
                }
                stack.addLast(x);
            }
            while (!stack.isEmpty()) nxt.put(stack.pollLast(), -1);
            for (int i = 0; i < M; i++) {
                if (i > 0) out.append(' ');
                out.append(nxt.get(subset[i]));
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

