import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        M = next(it)
        subset = [next(it) for _ in range(M)]
        N = next(it)
        full = [next(it) for _ in range(N)]
        nxt = {}
        stack = []
        for x in full:
            while stack and stack[-1] < x:
                nxt[stack.pop()] = x
            stack.append(x)
        while stack:
            nxt[stack.pop()] = -1
        out_lines.append(' '.join(str(nxt[v]) for v in subset))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

