const fs = require('fs');
const data = fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let outputs = [];
for(let t=0;t<T;t++){
  const M = data[idx++];
  const subset = data.slice(idx, idx+M); idx+=M;
  const N = data[idx++];
  const full = data.slice(idx, idx+N); idx+=N;
  const nxt = new Map();
  const stack = [];
  for(const x of full){
    while(stack.length && stack[stack.length-1] < x){
      nxt.set(stack.pop(), x);
    }
    stack.push(x);
  }
  while(stack.length){ nxt.set(stack.pop(), -1); }
  const line = subset.map(v=>nxt.get(v)).join(' ');
  outputs.push(line);
}
console.log(outputs.join('\n'));

